    def __init__(self):
        self.devices: Dict[str, DeviceInfo] = {}
        self.ip_to_mac: Dict[str, str] = {}
        self._mac_vendor_cache: Dict[str, str] = {}

    def process_packet(self, packet: Any) -> Optional[DeviceInfo]:
        """
        处理数据包并更新设备信息
        :param packet: ParsedPacket对象
        :return: DeviceInfo对象
        """
        from core.parser.protocol_parser import ParsedPacket

        mac = packet.src_mac if hasattr(packet, 'src_mac') and packet.src_mac else None
        ip = packet.src_ip if hasattr(packet, 'src_ip') and packet.src_ip else None
        hostname = None

        # 尝试从DNS或DHCP包获取hostname
        if hasattr(packet, 'layers'):
            dns_layer = packet.layers.get('DNS')
            if dns_layer:
                # 从DNS查询获取可能的hostname
                questions = dns_layer.get('questions', [])
                for q in questions:
                    if q.get('type') == 'A' or q.get('type') == 'PTR':
                        hostname = q.get('name')
                        break

        # 更新设备信息
        if mac:
            device = self.update_device(mac, ip, hostname)

            # 也更新目的MAC对应的设备（如果是广播/多播则忽略）
            dst_mac = packet.dst_mac if hasattr(packet, 'dst_mac') else None
            if dst_mac and dst_mac != 'ff:ff:ff:ff:ff:ff':
                self.update_device(dst_mac, packet.dst_ip)

            return device

        return None

    def update_device(self, mac: str, ip: str = None, hostname: str = None) -> DeviceInfo:
        """更新设备信息"""
        current_time = time.time()

        if mac not in self.devices:
            vendor = self._lookup_vendor(mac)
            self.devices[mac] = DeviceInfo(
                mac_address=mac,
                ip_addresses=set(),
                hostname=hostname,
                vendor=vendor,
                first_seen=current_time,
                last_seen=current_time,
                packet_count=0,
                byte_count=0,
                device_type=self._guess_device_type(mac, vendor)
            )

        device = self.devices[mac]
        device.last_seen = current_time
        device.packet_count += 1

        if ip:
            device.ip_addresses.add(ip)
            self.ip_to_mac[ip] = mac

        if hostname and not device.hostname:
            device.hostname = hostname

        return device

    def _lookup_vendor(self, mac: str) -> str:
        """根据MAC地址查找厂商"""
        # 使用缓存
        if mac in self._mac_vendor_cache:
            return self._mac_vendor_cache[mac]

        # 获取OUI前缀（前6个字符，格式 XX:XX:XX）
        oui_prefix = mac[:8].upper()

        # 在已知厂商中查找
        for vendor, prefixes in self.VENDOR_OUI.items():
            if oui_prefix in prefixes:
                self._mac_vendor_cache[mac] = vendor
                return vendor

        # 尝试使用mac-vendor-lookup库
        try:
            from mac_vendor_lookup import MacLookup
            mac_lookup = MacLookup()
            vendor = mac_lookup.lookup(mac)
            self._mac_vendor_cache[mac] = vendor
            return vendor
        except:
            pass

        return "Unknown"

    def _guess_device_type(self, mac: str, vendor: str) -> str:
        """根据厂商猜测设备类型"""
        device_type_map = {
            'Apple': 'Phone/Tablet/Mac',
            'Samsung': 'Phone/Tablet',
            'Huawei': 'Phone/Tablet',
            'Cisco': 'Network Device',
            'Intel': 'PC/Laptop',
            'Dell': 'PC/Laptop',
            'HP': 'PC/Laptop/Printer',
            'Microsoft': 'PC/Xbox',
        }

        return device_type_map.get(vendor, 'Unknown')

    def get_device_by_mac(self, mac: str) -> Optional[DeviceInfo]:
        """根据MAC获取设备"""
        return self.devices.get(mac)

    def get_device_by_ip(self, ip: str) -> Optional[DeviceInfo]:
        """根据IP获取设备"""
        mac = self.ip_to_mac.get(ip)
        if mac:
            return self.devices.get(mac)
        return None

    def get_all_devices(self) -> List[DeviceInfo]:
        """获取所有设备"""
        return list(self.devices.values())

    def get_active_devices(self, timeout: int = 300) -> List[DeviceInfo]:
        """
        获取活跃设备
        :param timeout: 超时时间（秒），超过此时间未活跃的设备视为离线
        :return: 活跃设备列表
        """
        current_time = time.time()
        active_devices = []

        for device in self.devices.values():
            if current_time - device.last_seen < timeout:
                device.is_active = True
                active_devices.append(device)
            else:
                device.is_active = False

        return active_devices

    def get_device_count(self) -> int:
        """获取设备数量"""
        return len(self.devices)

    def get_active_device_count(self, timeout: int = 300) -> int:
        """获取活跃设备数量"""
        return len(self.get_active_devices(timeout))

    def clear_devices(self) -> None:
        """清除所有设备"""
        self.devices.clear()
        self.ip_to_mac.clear()
        self._mac_vendor_cache.clear()

    def get_top_devices_by_traffic(self, n: int = 10) -> List[DeviceInfo]:
        """
        获取流量最大的设备
        :param n: 返回数量
        """
        sorted_devices = sorted(
            self.devices.values(),
            key=lambda d: d.packet_count,
            reverse=True
        )
        return sorted_devices[:n]